#!/usr/bin/env node
/**
 * generate-with-claude.js
 *
 * Uses the Anthropic Claude API to generate a fully styled, personalised
 * guestbook page from a guest's metadata.
 *
 * Environment:
 *   ANTHROPIC_API_KEY  — the CLAUDE secret value
 *   GUEST_USERNAME     — sanitised GitHub username
 *   GUEST_DISPLAY_NAME — display name (HTML-escaped)
 *   GUEST_DESCRIPTION  — short bio (HTML-escaped)
 *   GUEST_CATEGORIES   — comma-separated categories
 *   GUEST_WEBSITE      — validated website URL (may be empty)
 *   GUEST_ISSUE_NUMBER — originating issue number
 *   GUEST_SIGNED_DATE  — "Month YYYY" date string
 *
 * Writes the generated HTML to stdout so the caller can capture it.
 */

'use strict';

const https = require('https');

const ANTHROPIC_API_KEY  = process.env.ANTHROPIC_API_KEY  || '';
const GUEST_USERNAME     = process.env.GUEST_USERNAME     || 'guest';
const GUEST_DISPLAY_NAME = process.env.GUEST_DISPLAY_NAME || GUEST_USERNAME;
const GUEST_DESCRIPTION  = process.env.GUEST_DESCRIPTION  || '';
const GUEST_CATEGORIES   = process.env.GUEST_CATEGORIES   || '';
const GUEST_WEBSITE      = process.env.GUEST_WEBSITE      || '';
const GUEST_ISSUE_NUMBER = process.env.GUEST_ISSUE_NUMBER || '0';
const GUEST_SIGNED_DATE  = process.env.GUEST_SIGNED_DATE  || '';

if (!ANTHROPIC_API_KEY) {
  process.stderr.write('ERROR: ANTHROPIC_API_KEY is not set.\n');
  process.exit(1);
}

const systemPrompt = `You are an expert web developer creating beautiful, personalised guestbook pages for the Moltnook platform — a collaborative GitHub Pages hub for builders, agents, and creators.

Moltnook's design system uses:
- Dark background: #0d0f14
- Card background: rgba(255,255,255,0.04) with border rgba(255,255,255,0.08)
- Accent colours: --accent: #7c6fff (purple), --accent2: #00d4ff (cyan), --accent3: #ff6bff (pink)
- Text: #e8eaf0 (primary), #8892a4 (muted)
- Border radius: 0.75rem
- Font: system-ui, -apple-system, sans-serif
- The shared stylesheet is at ../../styles.css (relative to the guest page)

Your pages must:
1. Be complete, valid HTML5 documents starting with <!DOCTYPE html>
2. Link to ../../styles.css for shared styles
3. NOT contain any <script> tags, inline event handlers (onclick=, onload=, etc.), or javascript: URIs
4. NOT contain any external resources other than the shared stylesheet
5. Have a navigation bar linking back to Moltnook (../../index.html) and the guestbook (../index.html)
6. Be visually stunning with CSS-only animations and creative layouts
7. Showcase the guest's identity, categories, and description in an engaging way
8. Include a footer with © and "Moltnook · MIT License"

Return ONLY the complete HTML document — no markdown, no code fences, no explanation.`;

const userPrompt = `Create a stunning, fully personalised guestbook page for:

- GitHub Username: ${GUEST_USERNAME}
- Display Name: ${GUEST_DISPLAY_NAME}
- Description: ${GUEST_DESCRIPTION}
- Tool Categories: ${GUEST_CATEGORIES}
- Website: ${GUEST_WEBSITE || '(none)'}
- Signed: ${GUEST_SIGNED_DATE}
- Issue: #${GUEST_ISSUE_NUMBER}

Make it visually impressive and unique — CSS animations, creative grid layouts, glowing accents. The page should feel like a personal showcase, not just a data card. Use the Moltnook design system colours and link to ../../styles.css.`;

/**
 * Call the Anthropic Messages API over plain HTTPS (no SDK required).
 */
function callClaude(system, user) {
  return new Promise((resolve, reject) => {
    const body = JSON.stringify({
      model: 'claude-opus-4-5',
      max_tokens: 4096,
      system,
      messages: [{ role: 'user', content: user }],
    });

    const options = {
      hostname: 'api.anthropic.com',
      path: '/v1/messages',
      method: 'POST',
      headers: {
        'x-api-key': ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json',
        'content-length': Buffer.byteLength(body),
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        if (res.statusCode !== 200) {
          reject(new Error(`Anthropic API returned ${res.statusCode}: ${data}`));
          return;
        }
        try {
          const parsed = JSON.parse(data);
          const text = parsed.content && parsed.content[0] && parsed.content[0].text;
          if (!text) {
            reject(new Error('Unexpected Anthropic API response shape.'));
            return;
          }
          resolve(text);
        } catch (e) {
          reject(new Error(`Failed to parse Anthropic API response: ${e.message}`));
        }
      });
    });

    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

/**
 * Basic safety check — reject HTML that contains unsafe patterns even when
 * generated by Claude (defensive coding).
 */
function isSafe(html) {
  const UNSAFE = [
    /<script\b/i,
    /\bon[a-z]+\s*=/i,
    /javascript\s*:/i,
    /vbscript\s*:/i,
    /data\s*:\s*text\/html/i,
  ];
  return !UNSAFE.some((p) => p.test(html));
}

(async () => {
  try {
    process.stderr.write(`Calling Claude to generate page for ${GUEST_USERNAME}...\n`);
    const html = await callClaude(systemPrompt, userPrompt);

    if (!html.trim().toLowerCase().startsWith('<!doctype html')) {
      process.stderr.write('ERROR: Claude response does not start with <!DOCTYPE html>.\n');
      process.exit(1);
    }

    if (!isSafe(html)) {
      process.stderr.write('ERROR: Claude-generated HTML contains unsafe patterns.\n');
      process.exit(1);
    }

    process.stdout.write(html);
    process.stderr.write(`Claude page generation complete for ${GUEST_USERNAME}.\n`);
  } catch (err) {
    process.stderr.write(`ERROR: ${err.message}\n`);
    process.exit(1);
  }
})();
